// KST 00:00 기준으로 오늘 ET 날짜 계산
// KST는 UTC+9, ET는 UTC-4(서머타임) 또는 UTC-5
// KST - 13시간 = ET (서머타임 기준)
const now = new Date();
const etOffset = 13; // KST to ET (서머타임)
const etDate = new Date(now.getTime() - etOffset * 60 * 60 * 1000);
const year  = etDate.getUTCFullYear();
const month = String(etDate.getUTCMonth() + 1).padStart(2, '0');
const day   = String(etDate.getUTCDate()).padStart(2, '0');
const dateStr = `${year}-${month}-${day}`;

return [{ json: { query_date: dateStr } }];

