### 날씨 정보
- 기온: {{ $json.game_context.weather.temperature }}°C
- 습도: {{ $json.game_context.weather.humidity }}%
- 풍속: {{ $json.game_context.weather.windSpeed }}m/s
- 풍향: {{ $json.game_context.weather.windDirection }}°
- 강수 확률: {{ $json.game_context.weather.precipitationProbability }}%

### 선발 투수 ID
{{ $json.game_context.pitcher_id }}

### 타선 구성 및 최근 성적
{{ JSON.stringify($json.batter_profiles, null, 2) }}

위 데이터를 분석하여 오늘 경기 전술 컨텍스트 JSON을 반환해라.

parameters.jsCode:
// 최종 컨텍스트 조립 + 파일 저장
const aggregate = $('타자 데이터 집계').item.json;
const aiRaw     = $input.first().json.output ?? '{}';

let aiAnalysis;
try {
  aiAnalysis = JSON.parse(aiRaw);
} catch (e) {
  aiAnalysis = { context_summary: aiRaw, weather_impact: '', key_matchups: [], hot_batters: [], cold_batters: [], recommended_focus: '' };
}

const context = {
  game_pk:        aggregate.game_context.game_pk,
  game_date:      aggregate.game_context.game_date,
  game_datetime:  aggregate.game_context.game_datetime,
  home_team:      aggregate.game_context.home_team,
  away_team:      aggregate.game_context.away_team,
  venue_name:     aggregate.game_context.venue_name,
  venue_dome:     aggregate.game_context.venue_dome,
  weather:        aggregate.game_context.weather,
  pitcher_id:     aggregate.game_context.pitcher_id,
  catcher_id:     aggregate.game_context.catcher_id,
  fielder_ids:    aggregate.game_context.fielder_ids,
  batter_profiles: aggregate.batter_profiles,
  ai_analysis:    aiAnalysis,
  created_at:     new Date().toISOString()
};

// 파일 경로: /tmp/pitchflow_context_{game_pk}.json
const filePath = `/tmp/pitchflow_context_${context.game_pk}.json`;
const fs = require('fs');
fs.writeFileSync(filePath, JSON.stringify(context, null, 2), 'utf8');

console.log(`컨텍스트 저장 완료: ${filePath}`);

return [{ json: { success: true, game_pk: context.game_pk, file_path: filePath, context } }];
